PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?durationInMinutes
WHERE {
  VALUES ?series { wd:Q3511178 wd:Q14870260 wd:Q56692089 }
  ?game wdt:P2107 ?series .
  {
    ?game wdt:P3784 wd:Q13927
  } UNION {
    ?game wdt:P2869 wd:Q13927
  }
  ?game wdt:P2047 ?duration .
  ?duration wdt:P1192 ?durationValue .
  ?duration wdt:P2159 ?durationUnit .
  BIND(CASE
    WHEN ?durationUnit = wd:P2127 THEN ?durationValue
    WHEN ?durationUnit = wd:P2128 THEN ?durationValue * 60
    WHEN ?durationUnit = wd:P2289 THEN ?durationValue / 60
    ELSE 0
  END AS ?durationInMinutes)
}
ORDER BY DESC(?durationInMinutes)
LIMIT 1

